#include<bits/stdc++.h>
using namespace std;
struct segment_tree
{
	struct node
	{
		int l,r,sum;
		int lson,rson;
		int tag;
		node():tag(0){}
	}a[200010];
	int cnt;
	segment_tree():cnt(0){}
	void pushup(int x)
	{
		a[x].sum=(a[a[x].lson].sum+a[a[x].rson].sum);
	}
	void pushdown(int x)
	{
		int mid=(a[x].l+a[x].r)>>1;
		int ls=a[x].lson,rs=a[x].rson;
		int tg=a[x].tag;
		a[ls].sum+=(mid-a[x].l+1)*tg;
		a[rs].sum+=(a[x].r-mid)*tg;
		a[ls].tag+=tg;
		a[rs].tag+=tg;
		a[x].tag=0;
	}
	int init(int l,int r)
	{
		int x=++cnt,mid=(l+r)>>1;
		a[x].l=l;
		a[x].r=r;
		if(l==r)
		{
			a[x].sum=0;
			return x;
		}
		a[x].lson=init(l,mid);
		a[x].rson=init(mid+1,r);
		pushup(x);
		return x;
	}
	void add(int x,int l,int r,int z)
	{
		if(a[x].l>r||a[x].r<l)
		{
			return;
		}
		if(l<=a[x].l&&a[x].r<=r)
		{
			a[x].sum=(a[x].sum+((a[x].r-a[x].l+1)*z));
			a[x].tag+=z;
			return;
		}
		pushdown(x);
		add(a[x].lson,l,r,z);
		add(a[x].rson,l,r,z);
		pushup(x);
	}
	int getsum(int x,int l,int r)
	{
		if(a[x].l>r||a[x].r<l)
		{
			return 0;
		}
		if(a[x].l>=l&&a[x].r<=r)
		{
			return a[x].sum;
		}
		pushdown(x);
		return (getsum(a[x].lson,l,r)+getsum(a[x].rson,l,r));
	}
}l,r;
int main()
{
    int n,m;
    scanf("%d%d",&n,&m);
    l.init(1,n);
    r.init(1,n);
    for(int i=1;i<=m;i++)
    {
        int q,a,b;
        scanf("%d%d%d",&q,&a,&b);
        if(q==1)
        {
            l.add(1,a,a,1);
            r.add(1,b,b,1);
        }
        else
        {
            printf("%d\n",l.getsum(1,1,b)-r.getsum(1,1,a-1));
        }
    }
    return 0;
}
